import os
import numpy as np
from typing import List, Dict, Tuple
import json
import pickle
from pathlib import Path
import re


class SimpleVectorDB:
    def __init__(self, dimension: int = 384):
        self.dimension = dimension
        self.vectors = []
        self.metadata = []
        self.index = 0
        
    def add(self, vector: np.ndarray, metadata: Dict):
        self.vectors.append(vector)
        self.metadata.append(metadata)
        
    def search(self, query_vector: np.ndarray, top_k: int = 5) -> List[Tuple[Dict, float]]:
        if not self.vectors:
            return []
        
        vectors_array = np.array(self.vectors)
        similarities = np.dot(vectors_array, query_vector) / (
            np.linalg.norm(vectors_array, axis=1) * np.linalg.norm(query_vector)
        )
        
        top_indices = np.argsort(similarities)[-top_k:][::-1]
        results = [(self.metadata[i], float(similarities[i])) for i in top_indices]
        return results
    
    def save(self, filepath: str):
        with open(filepath, 'wb') as f:
            pickle.dump({'vectors': self.vectors, 'metadata': self.metadata}, f)
    
    def load(self, filepath: str):
        with open(filepath, 'rb') as f:
            data = pickle.load(f)
            self.vectors = data['vectors']
            self.metadata = data['metadata']


class SimpleEmbedding:
    def __init__(self, dimension: int = 384):
        self.dimension = dimension
        np.random.seed(42)
        
    def _simple_hash_embedding(self, text: str) -> np.ndarray:
        words = text.lower().split()
        embedding = np.zeros(self.dimension)
        
        for word in words:
            hash_val = hash(word)
            for i in range(self.dimension):
                seed = hash_val + i
                np.random.seed(seed & 0xFFFFFFFF)
                embedding[i] += np.random.randn()
        
        if len(words) > 0:
            embedding /= len(words)
        
        norm = np.linalg.norm(embedding)
        if norm > 0:
            embedding = embedding / norm
            
        return embedding
    
    def embed(self, text: str) -> np.ndarray:
        return self._simple_hash_embedding(text)


class DocumentProcessor:
    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 50):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap
    
    def load_documents(self, directory: str) -> List[Dict]:
        documents = []
        path = Path(directory)
        
        if not path.exists():
            return documents
        
        for file_path in path.rglob('*'):
            if file_path.is_file() and file_path.suffix in ['.txt', '.md', '.json']:
                try:
                    with open(file_path, 'r', encoding='utf-8') as f:
                        content = f.read()
                        documents.append({
                            'filename': file_path.name,
                            'filepath': str(file_path),
                            'content': content
                        })
                except Exception as e:
                    print(f"Error loading {file_path}: {e}")
        
        return documents
    
    def chunk_text(self, text: str) -> List[str]:
        chunks = []
        start = 0
        text_length = len(text)
        
        while start < text_length:
            end = start + self.chunk_size
            chunk = text[start:end]
            chunks.append(chunk)
            start += self.chunk_size - self.chunk_overlap
        
        return chunks
    
    def process_documents(self, documents: List[Dict]) -> List[Dict]:
        processed_chunks = []
        
        for doc in documents:
            chunks = self.chunk_text(doc['content'])
            for i, chunk in enumerate(chunks):
                processed_chunks.append({
                    'filename': doc['filename'],
                    'filepath': doc['filepath'],
                    'chunk_id': i,
                    'content': chunk,
                    'total_chunks': len(chunks)
                })
        
        return processed_chunks


class SimpleLLM:
    def __init__(self):
        pass
    
    def generate(self, prompt: str, max_length: int = 500) -> str:
        response = f"Based on the provided context, here is a synthesized answer:\n\n"
        response += "This is a simulated LLM response. In a production system, this would call an actual LLM API "
        response += "(like OpenAI GPT, Anthropic Claude, or a local model) with the full prompt containing "
        response += "the user query and all retrieved context documents.\n\n"
        response += f"Query processed: {len(prompt)} characters in prompt.\n"
        response += "The response would be generated based on the retrieved context passages."
        
        return response


class RAGSystem:
    def __init__(self, embedding_dim: int = 384, db_path: str = 'vector_db.pkl'):
        self.embedding_model = SimpleEmbedding(dimension=embedding_dim)
        self.vector_db = SimpleVectorDB(dimension=embedding_dim)
        self.doc_processor = DocumentProcessor()
        self.llm = SimpleLLM()
        self.db_path = db_path
        
    def load_and_index_documents(self, document_directory: str):
        print(f"Loading documents from {document_directory}...")
        documents = self.doc_processor.load_documents(document_directory)
        print(f"Loaded {len(documents)} documents")
        
        print("Processing and chunking documents...")
        chunks = self.doc_processor.process_documents(documents)
        print(f"Created {len(chunks)} chunks")
        
        print("Generating embeddings and indexing...")
        for chunk in chunks:
            embedding = self.embedding_model.embed(chunk['content'])
            self.vector_db.add(embedding, chunk)
        
        print(f"Indexed {len(chunks)} chunks into vector database")
        
        print(f"Saving vector database to {self.db_path}...")
        self.vector_db.save(self.db_path)
        print("Vector database saved successfully")
    
    def load_index(self):
        if os.path.exists(self.db_path):
            print(f"Loading existing vector database from {self.db_path}...")
            self.vector_db.load(self.db_path)
            print(f"Loaded {len(self.vector_db.vectors)} vectors")
            return True
        else:
            print(f"No existing database found at {self.db_path}")
            return False
    
    def retrieve_context(self, query: str, top_k: int = 5) -> List[Dict]:
        query_embedding = self.embedding_model.embed(query)
        results = self.vector_db.search(query_embedding, top_k=top_k)
        
        context_docs = []
        for metadata, score in results:
            context_docs.append({
                'content': metadata['content'],
                'filename': metadata['filename'],
                'chunk_id': metadata['chunk_id'],
                'similarity_score': score
            })
        
        return context_docs
    
    def create_prompt(self, query: str, context_docs: List[Dict]) -> str:
        prompt = "You are a helpful assistant answering questions based on company knowledge base documents.\n\n"
        prompt += "Retrieved Context Documents:\n"
        prompt += "=" * 80 + "\n\n"
        
        for i, doc in enumerate(context_docs, 1):
            prompt += f"Document {i} (from {doc['filename']}, chunk {doc['chunk_id']}, similarity: {doc['similarity_score']:.4f}):\n"
            prompt += "-" * 80 + "\n"
            prompt += doc['content']
            prompt += "\n" + "=" * 80 + "\n\n"
        
        prompt += f"User Query: {query}\n\n"
        prompt += "Instructions: Based on the context documents provided above, please answer the user's query. "
        prompt += "If the answer is not contained in the documents, say so. Provide specific references to the documents when possible.\n\n"
        prompt += "Answer:"
        
        return prompt
    
    def query(self, user_query: str, top_k: int = 5) -> Dict:
        print(f"\nProcessing query: {user_query}")
        
        print(f"Retrieving top {top_k} relevant documents...")
        context_docs = self.retrieve_context(user_query, top_k=top_k)
        
        print(f"Retrieved {len(context_docs)} context documents")
        
        print("Creating prompt with all context...")
        prompt = self.create_prompt(user_query, context_docs)
        
        print("Generating response from LLM...")
        response = self.llm.generate(prompt)
        
        return {
            'query': user_query,
            'context_documents': context_docs,
            'prompt': prompt,
            'response': response
        }


